mapper.select:
SELECT id, sku_id, location_id, available, reserved, version
FROM inventory
WHERE id = #{id}

mapper.update:
UPDATE inventory
SET sku_id = #{row.skuId},
    location_id = #{row.locationId},
    available = #{row.available},
    reserved = #{row.reserved},
    version = #{row.version}
WHERE id = #{row.id}
  AND version = #{expectedVersion}

mapper.delete:
DELETE FROM inventory
WHERE id = #{id}
  AND version = #{expectedVersion}
